import{c as t,Q as o,j as r,m as a}from"./chunks/framework.rlpw0eGz.js";const R=JSON.parse('{"title":"MySQL ORDER BY 性能问题","description":"MySQL ORDER BY 不同排序方向的性能差异分析与优化实践","frontmatter":{"title":"MySQL ORDER BY 性能问题","description":"MySQL ORDER BY 不同排序方向的性能差异分析与优化实践","date":"2026-05-30T00:00:00.000Z"},"headers":[],"relativePath":"notes/MySQL ORDER BY 性能问题.md","filePath":"notes/MySQL ORDER BY 性能问题.md","lastUpdated":null}'),d={name:"notes/MySQL ORDER BY 性能问题.md"};function s(c,e,i,n,l,_){return o(),r("div",null,[...e[0]||(e[0]=[a('<h3 id="mysql-order-by-性能问题" tabindex="-1">MySQL ORDER BY 性能问题 <a class="header-anchor" href="#mysql-order-by-性能问题" aria-label="Permalink to &quot;MySQL ORDER BY 性能问题&quot;">​</a></h3><p class="note-date">2026-05-30</p><h4 id="_1-order-by-id-asc-vs-desc" tabindex="-1">1. <code>ORDER BY id ASC</code> vs <code>DESC</code> <a class="header-anchor" href="#_1-order-by-id-asc-vs-desc" aria-label="Permalink to &quot;1. `ORDER BY id ASC` vs `DESC`&quot;">​</a></h4><p><code>id</code> 为主键（聚簇索引），性能取决于 MySQL 版本：</p><table tabindex="0"><thead><tr><th>版本</th><th>行为</th><th>性能</th></tr></thead><tbody><tr><td><strong>MySQL &lt; 8.0.13</strong></td><td>ASC 正向扫描叶子节点链表；DESC 反向遍历双向链表</td><td>DESC 慢 10%~30%</td></tr><tr><td><strong>MySQL ≥ 8.0.13</strong></td><td>引入 <strong>Backward Index Scan</strong> 优化</td><td>两者基本无差异</td></tr></tbody></table><p>验证方式：<code>EXPLAIN</code> 查看 <code>Extra</code> 列是否显示 <code>Backward index scan</code>。</p><hr><h4 id="_2-order-by-create-time-无索引时" tabindex="-1">2. <code>ORDER BY create_time</code>（无索引时） <a class="header-anchor" href="#_2-order-by-create-time-无索引时" aria-label="Permalink to &quot;2. `ORDER BY create_time`（无索引时）&quot;">​</a></h4><p>ASC 和 DESC 代价相同，流程固定：</p><ol><li><strong>全表扫描</strong> — 读取所有行</li><li><strong>filesort</strong> — 在内存或磁盘排序（取决于 <code>sort_buffer_size</code> 和数据量）</li></ol><p>表越大越慢。数据量超过 <code>sort_buffer_size</code> 时会使用磁盘临时文件，性能急剧下降。</p><h4 id="优化方案-按推荐顺序" tabindex="-1">优化方案（按推荐顺序） <a class="header-anchor" href="#优化方案-按推荐顺序" aria-label="Permalink to &quot;优化方案（按推荐顺序）&quot;">​</a></h4><ul><li>高频查询加<strong>复合索引</strong>：<code>(xxx, create_time)</code> 覆盖查询 + 排序</li><li>配合 <code>LIMIT n</code> + 合适索引 → 走 <strong>Using index</strong> 直接按索引顺序取，不走 filesort</li><li>无索引 + 大表 → 绝对避免无条件的 ORDER BY</li></ul>',13)])])}const S=t(d,[["render",s]]);export{R as __pageData,S as default};
